import{_ as a,a as t}from"./chunks/查询额度成功.wz9SQqrH.js";import{_ as o,o as n,c as d,a2 as l}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Een pCloud-kanaal toevoegen","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/upload/pcloud.md","filePath":"nl-NL/upload/pcloud.md","lastUpdated":1781962217000}'),i={name:"nl-NL/upload/pcloud.md"};function s(r,e,p,c,h,u){return n(),d("div",null,[...e[0]||(e[0]=[l('<h1 id="een-pcloud-kanaal-toevoegen" tabindex="-1">Een pCloud-kanaal toevoegen <a class="header-anchor" href="#een-pcloud-kanaal-toevoegen" aria-label="Permalink to &quot;Een pCloud-kanaal toevoegen&quot;">​</a></h1><h2 id="geschikt-voor" tabindex="-1">Geschikt voor <a class="header-anchor" href="#geschikt-voor" aria-label="Permalink to &quot;Geschikt voor&quot;">​</a></h2><ul><li>Je hebt een pCloud-account en wilt ImgBed-afbeeldingen in pCloud opslaan.</li><li>Je vindt het goed om het e-mailadres en wachtwoord van je pCloud-account als kanaalgegevens te gebruiken.</li></ul><h2 id="wat-je-vooraf-nodig-hebt" tabindex="-1">Wat je vooraf nodig hebt <a class="header-anchor" href="#wat-je-vooraf-nodig-hebt" aria-label="Permalink to &quot;Wat je vooraf nodig hebt&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Vereiste</th><th>Waarom je dit nodig hebt</th></tr></thead><tbody><tr><td>E-mailadres pCloud-account</td><td>Voor aanmelden bij de pCloud API</td></tr><tr><td>pCloud-wachtwoord</td><td>Voor aanmelden bij de pCloud API</td></tr><tr><td>API-host</td><td>Standaard <code>api.pcloud.com</code>. EU-accounts kunnen <code>eapi.pcloud.com</code> gebruiken.</td></tr><tr><td>Opslagmap</td><td>Waar bestanden worden opgeslagen. Standaard <code>imgbed</code>.</td></tr></tbody></table><h2 id="waar-je-het-toevoegt" tabindex="-1">Waar je het toevoegt <a class="header-anchor" href="#waar-je-het-toevoegt" aria-label="Permalink to &quot;Waar je het toevoegt&quot;">​</a></h2><ol><li>Open Systeeminstellingen.</li><li>Open Uploadinstellingen.</li><li>Klik rechtsboven op <code>Kanaal toevoegen</code>.</li><li>Kies <code>pCloud</code>.</li></ol><h2 id="veldreferentie" tabindex="-1">Veldreferentie <a class="header-anchor" href="#veldreferentie" aria-label="Permalink to &quot;Veldreferentie&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Veld</th><th>Doel</th><th>Verplicht</th></tr></thead><tbody><tr><td>Kanaalnaam</td><td>Herkent dit pCloud-kanaal, bijvoorbeeld <code>Personal pCloud</code></td><td>Ja</td></tr><tr><td>Account e-mail</td><td>Je pCloud-loginmail</td><td>Ja</td></tr><tr><td>Wachtwoord</td><td>Je pCloud-wachtwoord</td><td>Ja</td></tr><tr><td>API-host</td><td>pCloud API-host. Standaard <code>api.pcloud.com</code>.</td><td>Nee</td></tr><tr><td>Opslagmap</td><td>Map waarin bestanden worden opgeslagen. Standaard <code>imgbed</code>.</td><td>Nee</td></tr></tbody></table><p>Kies de API-host op basis van je accountregio:</p><table tabindex="0"><thead><tr><th>Accountregio</th><th>API-host</th></tr></thead><tbody><tr><td>Standaard / VS</td><td><code>api.pcloud.com</code></td></tr><tr><td>Europa</td><td><code>eapi.pcloud.com</code></td></tr></tbody></table><h2 id="instelstappen" tabindex="-1">Instelstappen <a class="header-anchor" href="#instelstappen" aria-label="Permalink to &quot;Instelstappen&quot;">​</a></h2><ol><li>Open Uploadinstellingen.</li><li>Klik op <code>Kanaal toevoegen</code>.</li><li>Kies <code>pCloud</code>.</li><li>Vul een herkenbare kanaalnaam in.</li><li>Vul het e-mailadres van je pCloud-account in.</li><li>Vul je pCloud-wachtwoord in.</li><li>Laat de API-host op <code>api.pcloud.com</code>, of gebruik <code>eapi.pcloud.com</code> voor EU-accounts.</li><li>Laat de opslagmap op <code>imgbed</code>, of kies een eigen map.</li><li>Sla het kanaal op.</li></ol><p><img src="'+a+'" alt="Kanaal configureren" loading="lazy"></p><h2 id="controleren" tabindex="-1">Controleren <a class="header-anchor" href="#controleren" aria-label="Permalink to &quot;Controleren&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Controle</th><th>Verwacht resultaat</th></tr></thead><tbody><tr><td>Kanaalkaart</td><td>De pCloud-kanaalkaart verschijnt na opslaan.</td></tr><tr><td>Kanaalschakelaar</td><td>De schakelaar op de kaart blijft ingeschakeld.</td></tr><tr><td>E-mailweergave</td><td>De kaart toont het gekoppelde pCloud-e-mailadres.</td></tr><tr><td>Quota-opvraag</td><td>Na een geslaagde opvraag worden gebruikte en totale capaciteit getoond.</td></tr><tr><td>Testupload</td><td>Een testafbeelding verschijnt in de ingestelde pCloud-opslagmap.</td></tr></tbody></table><p><img src="'+t+`" alt="Quota-opvraag gelukt" loading="lazy"></p><h2 id="problemen-oplossen" tabindex="-1">Problemen oplossen <a class="header-anchor" href="#problemen-oplossen" aria-label="Permalink to &quot;Problemen oplossen&quot;">​</a></h2><h3 id="waarom-geen-oauth2" tabindex="-1">Waarom geen OAuth2? <a class="header-anchor" href="#waarom-geen-oauth2" aria-label="Permalink to &quot;Waarom geen OAuth2?&quot;">​</a></h3><p>pCloud OAuth2 is standaard niet self-service. Je moet pCloud mailen en vragen om het in te schakelen.</p><p>De huidige pCloud OAuth2-flow ondersteunt bovendien niet de kortlevende uploadlinkflow die ImgBed nodig heeft. Daarom gebruikt dit kanaal login met accountmail en wachtwoord.</p><h3 id="welke-api-host-moet-ik-gebruiken" tabindex="-1">Welke API-host moet ik gebruiken? <a class="header-anchor" href="#welke-api-host-moet-ik-gebruiken" aria-label="Permalink to &quot;Welke API-host moet ik gebruiken?&quot;">​</a></h3><p>Standaard:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>api.pcloud.com</span></span></code></pre></div><p>Voor EU-accounts:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>eapi.pcloud.com</span></span></code></pre></div><h2 id="snelle-flow" tabindex="-1">Snelle flow <a class="header-anchor" href="#snelle-flow" aria-label="Permalink to &quot;Snelle flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bereid je pCloud-mail en wachtwoord voor</span></span>
<span class="line"><span>-&gt; Open Uploadinstellingen</span></span>
<span class="line"><span>-&gt; Kanaal toevoegen</span></span>
<span class="line"><span>-&gt; Kies pCloud</span></span>
<span class="line"><span>-&gt; Vul kanaalnaam / e-mail / wachtwoord in</span></span>
<span class="line"><span>-&gt; Laat API-host op api.pcloud.com tenzij je account in Europa staat</span></span>
<span class="line"><span>-&gt; Laat opslagmap op imgbed tenzij je een andere map nodig hebt</span></span>
<span class="line"><span>-&gt; Sla op</span></span>
<span class="line"><span>-&gt; Vraag quota op</span></span>
<span class="line"><span>-&gt; Upload een testafbeelding</span></span></code></pre></div>`,28)])])}const k=o(i,[["render",s]]);export{m as __pageData,k as default};
